# ALZ-Bicep parameter file customization examples
# Parameter files are JSON; edit before running deployment.

# 1. managementGroupsAll.parameters.all.json: customize MG names
cat > /tmp/mg-params.json << 'EOF'
{
  "$schema": "https://schema.management.azure.com/schemas/2019-04-01/deploymentParameters.json#",
  "contentVersion": "1.0.0.0",
  "parameters": {
    "parTopLevelManagementGroupPrefix": { "value": "alz" },
    "parTopLevelManagementGroupDisplayName": { "value": "Azure Landing Zones" },
    "parLandingZoneMgChildren": {
      "value": [
        { "id": "corp",    "displayName": "Corp" },
        { "id": "online",  "displayName": "Online" }
      ]
    }
  }
}
EOF

# 2. hubNetworking.parameters.prod.json: set hub address space and FW SKU
cat > /tmp/hub-params.json << 'EOF'
{
  "$schema": "https://schema.management.azure.com/schemas/2019-04-01/deploymentParameters.json#",
  "contentVersion": "1.0.0.0",
  "parameters": {
    "parLocation": { "value": "eastus" },
    "parHubNetworkAddressPrefix": { "value": "10.0.0.0/16" },
    "parAzFirewallEnabled": { "value": true },
    "parAzFirewallTier": { "value": "Premium" },
    "parAzFirewallAvailabilityZones": { "value": ["1", "2", "3"] },
    "parAzErGatewayEnabled": { "value": true },
    "parAzVpnGatewayEnabled": { "value": false },
    "parPrivateDnsZonesEnabled": { "value": true },
    "parPrivateDnsZones": {
      "value": [
        "privatelink.blob.core.windows.net",
        "privatelink.vaultcore.azure.net",
        "privatelink.database.windows.net",
        "privatelink.servicebus.windows.net",
        "privatelink.azurecr.io"
      ]
    }
  }
}
EOF

echo 'Parameter files ready. Review before deploying.'
